#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

int main() {
    // Basic lambda:
    auto greet = [](string name) { cout << "Hello, " << name << "!" << endl; };
    greet("Alice");
    greet("Bob");

    // Lambda as comparator:
    vector<int> nums = {5, 2, 8, 1, 9};
    sort(nums.begin(), nums.end(), [](int a, int b){ return a > b; });
    for (int n : nums) cout << n << " ";
    cout << endl;

    // Lambda with return type deduction:
    auto square = [](int n) { return n * n; };
    cout << square(7) << endl;

    return 0;
}

instruction:
Lambdas can capture outer variables:

```cpp
int threshold = 60;
auto isPassing = [threshold](int score) {
    return score >= threshold;
};
```

- `[threshold]` — capture by value (copy)
- `[&threshold]` — capture by reference
- `[=]` — capture all used variables by value
- `[&]` — capture all by reference

