#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

int main() {
    int threshold = 60;

    auto isPassing = [threshold](int score) {
        return score >= threshold;  // uses captured threshold
    };

    vector<int> scores = {45, 72, 88, 55, 90, 38};
    int passing = count_if(scores.begin(), scores.end(), isPassing);
    cout << "Passing: " << passing << endl;

    // Capture by reference — lambda can modify outer variable:
    int sum = 0;
    for_each(scores.begin(), scores.end(), [&sum](int s){ sum += s; });
    cout << "Sum: " << sum << endl;

    return 0;
}

#include <iostream>
#include <functional>
#include <vector>
#include <string>
using namespace std;

void applyToAll(vector<int>& v, function<int(int)> transform) {
    for (auto& x : v) x = transform(x);
}

int main() {
    vector<int> nums = {1, 2, 3, 4, 5};

    applyToAll(nums, [](int n){ return n * 2; });
    for (int n : nums) cout << n << " ";
    cout << endl;

    applyToAll(nums, [](int n){ return n + 10; });
    for (int n : nums) cout << n << " ";
    cout << endl;

    // Store different callbacks:
    function<void(string)> onLogin;
    onLogin = [](string user){ cout << user << " logged in." << endl; };
    onLogin("Alice");

    return 0;
}

instruction:
Functions can return lambdas — this creates closures, encapsulating state:

```cpp
auto makeCounter() {
    int count = 0;
    return [count]() mutable { return ++count; };
}
```

`mutable` allows the lambda to modify captured-by-value variables.

