#include <iostream>
#include <functional>
using namespace std;

auto makeMultiplier(int factor) {
    return [factor](int n){ return n * factor; };  // factor captured
}

auto makeCounter() {
    int count = 0;
    return [count]() mutable { return ++count; };  // mutable to modify copy
}

int main() {
    auto triple = makeMultiplier(3);
    auto double_ = makeMultiplier(2);

    cout << triple(5)  << endl;   // 15
    cout << double_(7) << endl;   // 14

    auto counter1 = makeCounter();
    auto counter2 = makeCounter();
    cout << counter1() << endl;   // 1
    cout << counter1() << endl;   // 2
    cout << counter2() << endl;   // 1 (own counter)

    return 0;
}
